import type { ThreadId, ThreadStatus } from "@t3tools/contracts";

/**
 * workstreamGraph - the single pure source of truth for the workstream graph:
 * structure (lineage), membership (which threads share one orchestration tree),
 * and the generation join the dispatcher uses to wake a parent.
 *
 * Mirrors the `workstreamDependencies` precedent: a minimal structural node
 * shape both the read-model thread (`OrchestrationThread`) and the shell summary
 * (`OrchestrationThreadShell`) satisfy, plus pure predicates consumed by every
 * graph walker (dispatcher join, same-tree auth, discovery view) so they can
 * never disagree. No I/O.
 *
 * @module workstreamGraph
 */

/**
 * Minimal structural node shape. Both `OrchestrationThread` and
 * `OrchestrationThreadShell` satisfy it. Lineage (`parentThreadId`) is the only
 * edge needed for structure + membership; generation grouping reads
 * `spawnGeneration`/`status`.
 */
export interface GraphThread extends GraphLineageNode {
  readonly spawnGeneration: string | null;
  readonly status: ThreadStatus;
  readonly role: string | null;
  readonly title: string | null;
}

/**
 * The minimal lineage shape the structural walkers (root/descendants/subtree)
 * actually read: an id and its parent edge. Both the full `GraphThread` and the
 * leaner cost-rollup node satisfy it, so the same index/walk serves both.
 */
export interface GraphLineageNode {
  readonly id: ThreadId;
  readonly parentThreadId: ThreadId | null;
}

interface GraphIndex<T extends GraphLineageNode> {
  readonly byId: ReadonlyMap<ThreadId, T>;
  readonly childrenByParent: ReadonlyMap<ThreadId, ReadonlyArray<T>>;
}

/** Build the adjacency index once (id lookup + parent→children) from a node set. */
const buildIndex = <T extends GraphLineageNode>(threads: ReadonlyArray<T>): GraphIndex<T> => {
  const byId = new Map<ThreadId, T>();
  const childrenByParent = new Map<ThreadId, T[]>();
  for (const thread of threads) {
    byId.set(thread.id, thread);
    if (thread.parentThreadId !== null) {
      const siblings = childrenByParent.get(thread.parentThreadId);
      if (siblings) siblings.push(thread);
      else childrenByParent.set(thread.parentThreadId, [thread]);
    }
  }
  return { byId, childrenByParent };
};

/**
 * Walk ancestors to the root orchestrator. The root is the first node reached
 * with `parentThreadId === null` (a top-level thread). A node whose parent is
 * unknown (dangling/out-of-snapshot) is its own subtree root; a cycle is broken
 * by a visited guard, returning the id where the walk re-enters itself.
 */
const rootOf = <T extends GraphLineageNode>(id: ThreadId, index: GraphIndex<T>): ThreadId => {
  const seen = new Set<ThreadId>();
  let current = id;
  for (;;) {
    if (seen.has(current)) return current;
    seen.add(current);
    const node = index.byId.get(current);
    if (node === undefined || node.parentThreadId === null) return current;
    current = node.parentThreadId;
  }
};

/** Direct children of a node (empty when it has none / is unknown). */
export const childrenOf = <T extends GraphLineageNode>(
  id: ThreadId,
  threads: ReadonlyArray<T>,
): ReadonlyArray<T> => buildIndex(threads).childrenByParent.get(id) ?? [];

const collectDescendants = <T extends GraphLineageNode>(
  id: ThreadId,
  index: GraphIndex<T>,
  out: T[],
  seen: Set<ThreadId>,
): void => {
  for (const child of index.childrenByParent.get(id) ?? []) {
    if (seen.has(child.id)) continue;
    seen.add(child.id);
    out.push(child);
    collectDescendants(child.id, index, out, seen);
  }
};

/** All transitive descendants of a node (excludes the node itself). */
export const descendantsOf = <T extends GraphLineageNode>(
  id: ThreadId,
  threads: ReadonlyArray<T>,
): ReadonlyArray<T> => {
  const out: T[] = [];
  collectDescendants(id, buildIndex(threads), out, new Set([id]));
  return out;
};

/** The node plus all its transitive descendants (the whole subtree rooted at it). */
export const subtreeOf = <T extends GraphLineageNode>(
  id: ThreadId,
  threads: ReadonlyArray<T>,
): ReadonlyArray<T> => {
  const index = buildIndex(threads);
  const node = index.byId.get(id);
  const out: T[] = node ? [node] : [];
  collectDescendants(id, index, out, new Set([id]));
  return out;
};

/**
 * A lineage node that also carries its own cumulative dollar cost — the input to
 * the context cost meter's subtree rollup. `cumulativeCostUsd` is each thread's
 * OWN spend; null/absent counts as 0 (e.g. providers that report no cost).
 */
export interface CostGraphNode extends GraphLineageNode {
  readonly cumulativeCostUsd: number | null;
}

/**
 * Total cost of the whole subtree rooted at `id` (the node plus all transitive
 * descendants), summing each node's own `cumulativeCostUsd`. Pure; reuses the
 * same lineage walk as `subtreeOf`, so a thread sitting at the orchestrator root
 * sees its entire workstream's spend.
 */
export const subtreeCostOf = <T extends CostGraphNode>(
  id: ThreadId,
  threads: ReadonlyArray<T>,
): number => subtreeOf(id, threads).reduce((sum, node) => sum + (node.cumulativeCostUsd ?? 0), 0);

/**
 * Membership predicate that powers same-tree authorization: two threads are in
 * the same workstream iff they share the same root orchestrator. This is the
 * single boundary used by both discovery (`graphViewFor`) and the read/ask tools
 * — least-privilege (one tree, never global) while still including siblings,
 * cousins, ancestors, and descendants within that one orchestration tree.
 *
 * A target absent from the snapshot is never "in tree" (callers distinguish a
 * missing target → 404 from an out-of-tree one → 403 by an existence check).
 */
export const isInSameTree = <T extends GraphLineageNode>(
  callerId: ThreadId,
  targetId: ThreadId,
  threads: ReadonlyArray<T>,
): boolean => {
  if (callerId === targetId) return true;
  const index = buildIndex(threads);
  if (!index.byId.has(targetId)) return false;
  return rootOf(callerId, index) === rootOf(targetId, index);
};

/**
 * A child is "terminal" for the join barrier when it has reached `done`,
 * `blocked`, `review`, or `error`. `planned`/`running` are not.
 *
 * `error` is included for ONE reason only (D-liveness decision 5): barrier
 * unblock — a generation containing an errored child can still *join* once the
 * rest are terminal, so an errored child no longer strands its siblings'
 * results forever. It is NOT the wake mechanism: an errored child among
 * still-running siblings won't fire this barrier, so the parent is woken
 * promptly through the per-child rail in `WorkstreamDispatcher` instead.
 * `error` also does NOT release dependents (that stays done-only in
 * `workstreamDependencies`).
 */
const TERMINAL_STATUSES: ReadonlySet<ThreadStatus> = new Set([
  "done",
  "blocked",
  "review",
  "error",
]);
export const isTerminalStatus = (status: ThreadStatus): boolean => TERMINAL_STATUSES.has(status);

/** The fields the generation join reads — a subset of `GraphThread`. */
type JoinGroupThread = Pick<GraphThread, "parentThreadId" | "spawnGeneration" | "status">;

export interface JoinedGeneration<T> {
  readonly parentId: ThreadId;
  readonly generation: string;
  readonly children: ReadonlyArray<T>;
}

/**
 * Pure generation-join selection: group every sub-thread by
 * (parentThreadId, spawnGeneration) and return the groups in which **every**
 * member is terminal. Generic over the concrete node type so the dispatcher gets
 * back full shells. Generation grouping stays internal — no consumer needs a
 * standalone `groupByGeneration`.
 *
 * Eligibility is a pure function of durable thread state, so it is fully
 * recomputable from the read model after a restart.
 */
export const selectJoinedGenerations = <T extends JoinGroupThread>(
  threads: ReadonlyArray<T>,
): ReadonlyArray<JoinedGeneration<T>> => {
  const groups = new Map<string, { parentId: ThreadId; generation: string; children: T[] }>();
  for (const thread of threads) {
    if (thread.parentThreadId === null || thread.spawnGeneration === null) continue;
    const key = `${thread.parentThreadId}::${thread.spawnGeneration}`;
    const group = groups.get(key);
    if (group) group.children.push(thread);
    else
      groups.set(key, {
        parentId: thread.parentThreadId,
        generation: thread.spawnGeneration,
        children: [thread],
      });
  }
  return [...groups.values()].filter((group) =>
    group.children.every((child) => isTerminalStatus(child.status)),
  );
};

/** The richer node shape the discovery view needs (lineage + report + waits-on). */
export interface GraphViewThread extends GraphThread {
  readonly reportPath: string | null;
  readonly blockedBy: ReadonlyArray<ThreadId>;
}

export interface GraphViewNode {
  readonly id: ThreadId;
  readonly parentThreadId: ThreadId | null;
  readonly role: string | null;
  readonly title: string | null;
  readonly status: ThreadStatus;
  readonly spawnGeneration: string | null;
  readonly hasReport: boolean;
}

export interface GraphEdge {
  readonly from: ThreadId;
  readonly to: ThreadId;
}

export interface GraphView {
  readonly rootId: ThreadId;
  readonly callerId: ThreadId;
  readonly nodes: ReadonlyArray<GraphViewNode>;
  /** Lineage edges, parent → child. */
  readonly lineageEdges: ReadonlyArray<GraphEdge>;
  /** Waits-on edges, blocked thread → dependency (within the tree). */
  readonly waitsOnEdges: ReadonlyArray<GraphEdge>;
}

/**
 * The discovery payload: the caller's whole workstream tree (rooted at the
 * caller's root orchestrator) as nodes + lineage edges + waits-on edges. This is
 * exactly the scope the same-tree auth predicate covers — you can only read/ask
 * what `list` shows you. Lean by construction (no message/activity bodies).
 */
export const graphViewFor = <T extends GraphViewThread>(
  callerId: ThreadId,
  threads: ReadonlyArray<T>,
): GraphView => {
  const index = buildIndex(threads);
  const rootId = rootOf(callerId, index);
  const members = subtreeOf(rootId, threads);
  const memberIds = new Set(members.map((thread) => thread.id));
  const nodes: GraphViewNode[] = members.map((thread) => ({
    id: thread.id,
    parentThreadId: thread.parentThreadId,
    role: thread.role,
    title: thread.title,
    status: thread.status,
    spawnGeneration: thread.spawnGeneration,
    hasReport: thread.reportPath !== null,
  }));
  const lineageEdges = members.flatMap((thread) =>
    thread.parentThreadId !== null && memberIds.has(thread.parentThreadId)
      ? [{ from: thread.parentThreadId, to: thread.id }]
      : [],
  );
  const waitsOnEdges = members.flatMap((thread) =>
    thread.blockedBy.flatMap((depId) =>
      memberIds.has(depId) ? [{ from: thread.id, to: depId }] : [],
    ),
  );
  return { rootId, callerId, nodes, lineageEdges, waitsOnEdges };
};

import {
  EventId,
  type OrchestrationCommand,
  type OrchestrationEvent,
  type OrchestrationReadModel,
} from "@t3tools/contracts";
import * as DateTime from "effect/DateTime";
import * as Crypto from "effect/Crypto";
import * as Effect from "effect/Effect";
import type * as PlatformError from "effect/PlatformError";

import { OrchestrationCommandInvariantError } from "./Errors.ts";
import {
  findGoalById,
  listGoalsByProjectId,
  listThreadsByProjectId,
  requireActiveGoalInProject,
  requireGoal,
  requireGoalAbsent,
  requireGoalActive,
  requireGoalNotDeleted,
  requireGoalParentTask,
  requireGoalTask,
  requireGoalTaskAbsent,
  requireProject,
  requireProjectAbsent,
  requireThread,
  requireThreadArchived,
  requireThreadAbsent,
  requireThreadNotArchived,
  requireUniqueGoalSlug,
} from "./commandInvariants.ts";
import { flattenGoalTasks } from "./goalTaskTree.ts";
import { projectEvent } from "./projector.ts";
import { areDependenciesSatisfied } from "@t3tools/shared/workstreamDependencies";

const nowIso = Effect.map(DateTime.now, DateTime.formatIso);

function withEventBase(
  input: Pick<OrchestrationCommand, "commandId"> & {
    readonly aggregateKind: OrchestrationEvent["aggregateKind"];
    readonly aggregateId: OrchestrationEvent["aggregateId"];
    readonly occurredAt: string;
    readonly metadata?: OrchestrationEvent["metadata"];
  },
): Effect.Effect<
  Omit<OrchestrationEvent, "sequence" | "type" | "payload">,
  PlatformError.PlatformError,
  Crypto.Crypto
> {
  return Crypto.Crypto.pipe(
    Effect.flatMap((crypto) =>
      crypto.randomUUIDv4.pipe(
        Effect.map((eventId) => ({
          eventId: EventId.make(eventId),
          aggregateKind: input.aggregateKind,
          aggregateId: input.aggregateId,
          occurredAt: input.occurredAt,
          commandId: input.commandId,
          causationEventId: null,
          correlationId: input.commandId,
          metadata: input.metadata ?? {},
        })),
      ),
    ),
  );
}

type PlannedOrchestrationEvent = Omit<OrchestrationEvent, "sequence">;

type DecideOrchestrationCommandResult =
  | PlannedOrchestrationEvent
  | ReadonlyArray<PlannedOrchestrationEvent>;

const decideCommandSequence = Effect.fn("decideCommandSequence")(function* ({
  commands,
  readModel,
}: {
  readonly commands: ReadonlyArray<OrchestrationCommand>;
  readonly readModel: OrchestrationReadModel;
}): Effect.fn.Return<
  ReadonlyArray<PlannedOrchestrationEvent>,
  OrchestrationCommandInvariantError | PlatformError.PlatformError,
  Crypto.Crypto
> {
  let nextReadModel = readModel;
  let nextSequence = readModel.snapshotSequence;
  const plannedEvents: PlannedOrchestrationEvent[] = [];

  for (const nextCommand of commands) {
    const decided = yield* decideOrchestrationCommand({
      command: nextCommand,
      readModel: nextReadModel,
    });
    const nextEvents = Array.isArray(decided) ? decided : [decided];
    for (const nextEvent of nextEvents) {
      plannedEvents.push(nextEvent);
      nextSequence += 1;
      nextReadModel = yield* projectEvent(nextReadModel, {
        ...nextEvent,
        sequence: nextSequence,
      }).pipe(Effect.orDie);
    }
  }

  return plannedEvents;
});

export const decideOrchestrationCommand = Effect.fn("decideOrchestrationCommand")(function* ({
  command,
  readModel,
}: {
  readonly command: OrchestrationCommand;
  readonly readModel: OrchestrationReadModel;
}): Effect.fn.Return<
  DecideOrchestrationCommandResult,
  OrchestrationCommandInvariantError | PlatformError.PlatformError,
  Crypto.Crypto
> {
  switch (command.type) {
    case "project.create": {
      yield* requireProjectAbsent({
        readModel,
        command,
        projectId: command.projectId,
      });

      return {
        ...(yield* withEventBase({
          aggregateKind: "project",
          aggregateId: command.projectId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "project.created",
        payload: {
          projectId: command.projectId,
          title: command.title,
          workspaceRoot: command.workspaceRoot,
          defaultModelSelection: command.defaultModelSelection ?? null,
          scripts: [],
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
    }

    case "project.meta.update": {
      yield* requireProject({
        readModel,
        command,
        projectId: command.projectId,
      });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "project",
          aggregateId: command.projectId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "project.meta-updated",
        payload: {
          projectId: command.projectId,
          ...(command.title !== undefined ? { title: command.title } : {}),
          ...(command.workspaceRoot !== undefined ? { workspaceRoot: command.workspaceRoot } : {}),
          ...(command.defaultModelSelection !== undefined
            ? { defaultModelSelection: command.defaultModelSelection }
            : {}),
          ...(command.scripts !== undefined ? { scripts: command.scripts } : {}),
          updatedAt: occurredAt,
        },
      };
    }

    case "project.delete": {
      yield* requireProject({
        readModel,
        command,
        projectId: command.projectId,
      });
      const activeThreads = listThreadsByProjectId(readModel, command.projectId).filter(
        (thread) => thread.deletedAt === null,
      );
      const activeGoals = listGoalsByProjectId(readModel, command.projectId).filter(
        (goal) => goal.deletedAt === null,
      );
      if ((activeThreads.length > 0 || activeGoals.length > 0) && command.force !== true) {
        return yield* new OrchestrationCommandInvariantError({
          commandType: command.type,
          detail: `Project '${command.projectId}' is not empty and cannot be deleted without force=true.`,
        });
      }
      if (activeThreads.length > 0 || activeGoals.length > 0) {
        return yield* decideCommandSequence({
          readModel,
          commands: [
            ...activeThreads.map(
              (thread): Extract<OrchestrationCommand, { type: "thread.delete" }> => ({
                type: "thread.delete",
                commandId: command.commandId,
                threadId: thread.id,
              }),
            ),
            ...activeGoals.map(
              (goal): Extract<OrchestrationCommand, { type: "goal.delete" }> => ({
                type: "goal.delete",
                commandId: command.commandId,
                goalId: goal.id,
              }),
            ),
            {
              type: "project.delete",
              commandId: command.commandId,
              projectId: command.projectId,
            },
          ],
        });
      }

      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "project",
          aggregateId: command.projectId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "project.deleted" as const,
        payload: {
          projectId: command.projectId,
          deletedAt: occurredAt,
        },
      };
    }

    case "goal.create": {
      yield* requireProject({ readModel, command, projectId: command.projectId });
      yield* requireGoalAbsent({ readModel, command, goalId: command.goalId });
      yield* requireUniqueGoalSlug({
        readModel,
        command,
        projectId: command.projectId,
        slug: command.slug,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "goal.created",
        payload: {
          goalId: command.goalId,
          projectId: command.projectId,
          slug: command.slug,
          title: command.title,
          description: command.description ?? "",
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
    }

    case "goal.meta.update": {
      yield* requireGoalNotDeleted({ readModel, command, goalId: command.goalId });
      const goal = yield* requireGoal({ readModel, command, goalId: command.goalId });
      if (command.slug !== undefined) {
        yield* requireUniqueGoalSlug({
          readModel,
          command,
          projectId: goal.projectId,
          slug: command.slug,
          exceptGoalId: command.goalId,
        });
      }
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "goal.meta-updated",
        payload: {
          goalId: command.goalId,
          ...(command.slug !== undefined ? { slug: command.slug } : {}),
          ...(command.title !== undefined ? { title: command.title } : {}),
          ...(command.description !== undefined ? { description: command.description } : {}),
          updatedAt: occurredAt,
        },
      };
    }

    case "goal.archive": {
      yield* requireGoalNotDeleted({ readModel, command, goalId: command.goalId });
      // Archiving a goal cascades DOWN to its active threads. We don't emit
      // goal.archived here: archiving the last active thread cascades the goal
      // archive itself (see thread.archive), so we route through that one path.
      const activeThreads = readModel.threads.filter(
        (thread) =>
          thread.goalId === command.goalId &&
          thread.deletedAt === null &&
          thread.archivedAt === null,
      );
      if (activeThreads.length > 0) {
        return yield* decideCommandSequence({
          readModel,
          commands: activeThreads.map(
            (thread): Extract<OrchestrationCommand, { type: "thread.archive" }> => ({
              type: "thread.archive",
              commandId: command.commandId,
              threadId: thread.id,
            }),
          ),
        });
      }
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "goal.archived",
        payload: { goalId: command.goalId, archivedAt: occurredAt, updatedAt: occurredAt },
      };
    }

    case "goal.unarchive": {
      yield* requireGoalNotDeleted({ readModel, command, goalId: command.goalId });
      // Inverse of goal.archive: unarchive every archived thread, and the first
      // thread.unarchive cascades the goal unarchive (see thread.unarchive).
      const archivedThreads = readModel.threads.filter(
        (thread) =>
          thread.goalId === command.goalId &&
          thread.deletedAt === null &&
          thread.archivedAt !== null,
      );
      if (archivedThreads.length > 0) {
        return yield* decideCommandSequence({
          readModel,
          commands: archivedThreads.map(
            (thread): Extract<OrchestrationCommand, { type: "thread.unarchive" }> => ({
              type: "thread.unarchive",
              commandId: command.commandId,
              threadId: thread.id,
            }),
          ),
        });
      }
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "goal.unarchived",
        payload: { goalId: command.goalId, updatedAt: occurredAt },
      };
    }

    case "goal.delete": {
      yield* requireGoal({ readModel, command, goalId: command.goalId });
      // Deleting a goal cascade-deletes its threads (the goal owns them), then
      // deletes the goal once empty. thread.delete has no goal cascade, so the
      // trailing goal.delete re-decides against an empty goal and emits the leaf.
      const threads = readModel.threads.filter(
        (thread) => thread.goalId === command.goalId && thread.deletedAt === null,
      );
      if (threads.length > 0) {
        return yield* decideCommandSequence({
          readModel,
          commands: [
            ...threads.map(
              (thread): Extract<OrchestrationCommand, { type: "thread.delete" }> => ({
                type: "thread.delete",
                commandId: command.commandId,
                threadId: thread.id,
              }),
            ),
            {
              type: "goal.delete",
              commandId: command.commandId,
              goalId: command.goalId,
            },
          ],
        });
      }
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "goal.deleted",
        payload: { goalId: command.goalId, deletedAt: occurredAt },
      };
    }

    case "goal.task.create": {
      const goal = yield* requireGoalActive({
        readModel,
        command,
        goalId: command.goalId,
      });
      yield* requireGoalTaskAbsent({ command, goal, taskId: command.taskId });
      if (command.parentTaskId !== null) {
        yield* requireGoalParentTask({ command, goal, parentTaskId: command.parentTaskId });
      }
      const siblings = flattenGoalTasks(goal.tasks).filter(
        (task) => (task.parentTaskId ?? null) === command.parentTaskId,
      );
      const position =
        command.position ??
        (siblings.length === 0 ? 0 : Math.max(...siblings.map((task) => task.position)) + 1);
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "goal.task-created",
        payload: {
          goalId: command.goalId,
          taskId: command.taskId,
          parentTaskId: command.parentTaskId,
          text: command.text,
          position,
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
    }

    case "goal.task.update": {
      // Task reparenting is intentionally disallowed for MVP: there is no
      // parentTaskId on this command, so the task tree cannot form a cycle.
      const goal = yield* requireGoalActive({
        readModel,
        command,
        goalId: command.goalId,
      });
      yield* requireGoalTask({ command, goal, taskId: command.taskId });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "goal.task-updated",
        payload: {
          goalId: command.goalId,
          taskId: command.taskId,
          ...(command.text !== undefined ? { text: command.text } : {}),
          ...(command.done !== undefined ? { done: command.done } : {}),
          ...(command.position !== undefined ? { position: command.position } : {}),
          updatedAt: occurredAt,
        },
      };
    }

    case "goal.task.delete": {
      const goal = yield* requireGoalActive({
        readModel,
        command,
        goalId: command.goalId,
      });
      yield* requireGoalTask({ command, goal, taskId: command.taskId });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "goal",
          aggregateId: command.goalId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "goal.task-deleted",
        payload: { goalId: command.goalId, taskId: command.taskId, deletedAt: occurredAt },
      };
    }

    case "thread.create": {
      yield* requireProject({
        readModel,
        command,
        projectId: command.projectId,
      });
      yield* requireThreadAbsent({
        readModel,
        command,
        threadId: command.threadId,
      });
      if (command.goalId != null) {
        yield* requireActiveGoalInProject({
          readModel,
          command,
          goalId: command.goalId,
          projectId: command.projectId,
        });
      }
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.created",
        payload: {
          threadId: command.threadId,
          projectId: command.projectId,
          ...(command.goalId !== undefined ? { goalId: command.goalId } : {}),
          ...(command.parentThreadId !== undefined
            ? { parentThreadId: command.parentThreadId }
            : {}),
          ...(command.role !== undefined ? { role: command.role } : {}),
          ...(command.purpose !== undefined ? { purpose: command.purpose } : {}),
          ...(command.brief !== undefined ? { brief: command.brief } : {}),
          // Seed the node's run-condition; drop self-references so a thread can
          // never block on itself (cycles/dangling ids tolerated permissively,
          // matching thread.dependencies.set).
          ...(command.blockedBy !== undefined
            ? { blockedBy: command.blockedBy.filter((id) => id !== command.threadId) }
            : {}),
          ...(command.spawnGeneration !== undefined
            ? { spawnGeneration: command.spawnGeneration }
            : {}),
          title: command.title,
          modelSelection: command.modelSelection,
          runtimeMode: command.runtimeMode,
          interactionMode: command.interactionMode,
          branch: command.branch,
          worktreePath: command.worktreePath,
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
    }

    case "thread.delete": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.deleted",
        payload: {
          threadId: command.threadId,
          deletedAt: occurredAt,
        },
      };
    }

    case "thread.archive": {
      const thread = yield* requireThreadNotArchived({
        readModel,
        command,
        threadId: command.threadId,
      });
      const occurredAt = yield* nowIso;
      const archivedEvent: PlannedOrchestrationEvent = {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.archived",
        payload: {
          threadId: command.threadId,
          archivedAt: occurredAt,
          updatedAt: occurredAt,
        },
      };
      // Cascade UP: archiving the last active thread of a goal archives the
      // goal too, so the sidebar never strands an empty goal header. (Inverse
      // of goal.archive, which cascades down to its threads.)
      const goalId = thread.goalId ?? null;
      if (goalId !== null) {
        const goal = findGoalById(readModel, goalId);
        const goalHasOtherActiveThread = readModel.threads.some(
          (other) =>
            other.goalId === goalId &&
            other.id !== thread.id &&
            other.deletedAt === null &&
            other.archivedAt === null,
        );
        if (
          goal &&
          goal.deletedAt === null &&
          goal.archivedAt === null &&
          !goalHasOtherActiveThread
        ) {
          return [
            archivedEvent,
            {
              ...(yield* withEventBase({
                aggregateKind: "goal",
                aggregateId: goalId,
                occurredAt,
                commandId: command.commandId,
              })),
              type: "goal.archived",
              payload: { goalId, archivedAt: occurredAt, updatedAt: occurredAt },
            },
          ];
        }
      }
      return archivedEvent;
    }

    case "thread.unarchive": {
      const thread = yield* requireThreadArchived({
        readModel,
        command,
        threadId: command.threadId,
      });
      const occurredAt = yield* nowIso;
      const unarchivedEvent: PlannedOrchestrationEvent = {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.unarchived",
        payload: {
          threadId: command.threadId,
          updatedAt: occurredAt,
        },
      };
      // Cascade UP: resurfacing a thread whose goal was archived (e.g. by the
      // last-thread cascade above) must unarchive the goal too, otherwise the
      // thread would point at an archived goal and vanish from the sidebar.
      const goalId = thread.goalId ?? null;
      if (goalId !== null) {
        const goal = findGoalById(readModel, goalId);
        if (goal && goal.deletedAt === null && goal.archivedAt !== null) {
          return [
            unarchivedEvent,
            {
              ...(yield* withEventBase({
                aggregateKind: "goal",
                aggregateId: goalId,
                occurredAt,
                commandId: command.commandId,
              })),
              type: "goal.unarchived",
              payload: { goalId, updatedAt: occurredAt },
            },
          ];
        }
      }
      return unarchivedEvent;
    }

    case "thread.meta.update": {
      const thread = yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      if (command.goalId != null) {
        yield* requireActiveGoalInProject({
          readModel,
          command,
          goalId: command.goalId,
          projectId: thread.projectId,
        });
      }
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.meta-updated",
        payload: {
          threadId: command.threadId,
          ...(command.title !== undefined ? { title: command.title } : {}),
          ...(command.modelSelection !== undefined
            ? { modelSelection: command.modelSelection }
            : {}),
          ...(command.branch !== undefined ? { branch: command.branch } : {}),
          ...(command.worktreePath !== undefined ? { worktreePath: command.worktreePath } : {}),
          ...(command.goalId !== undefined ? { goalId: command.goalId } : {}),
          ...(command.role !== undefined ? { role: command.role } : {}),
          ...(command.purpose !== undefined ? { purpose: command.purpose } : {}),
          updatedAt: occurredAt,
        },
      };
    }

    case "thread.runtime-mode.set": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.runtime-mode-set",
        payload: {
          threadId: command.threadId,
          runtimeMode: command.runtimeMode,
          updatedAt: occurredAt,
        },
      };
    }

    case "thread.interaction-mode.set": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.interaction-mode-set",
        payload: {
          threadId: command.threadId,
          interactionMode: command.interactionMode,
          updatedAt: occurredAt,
        },
      };
    }

    case "thread.status.set": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      // D-liveness server-only `error` guard (load-bearing chokepoint). The
      // decider is the only path every status write passes through. `error` is
      // a failure state the liveness sweep sets; clients/MCP must not forge it.
      // Server writers build a `server:`-prefixed commandId (the web/WS board
      // dispatches a bare UUID and cannot forge that prefix), so reject `error`
      // unless the command carries it. (The MCP boundary also filters `error`
      // out of its settable set as defence-in-depth.)
      if (command.status === "error" && !command.commandId.startsWith("server:")) {
        return yield* new OrchestrationCommandInvariantError({
          commandType: command.type,
          detail: "Status 'error' is server-only and cannot be set by clients.",
        });
      }
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.status-set",
        payload: {
          threadId: command.threadId,
          status: command.status,
          updatedAt: occurredAt,
        },
      };
    }

    case "thread.dependencies.set": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.dependencies-set",
        payload: {
          threadId: command.threadId,
          // Replace-set semantics; drop self-references so a thread can never
          // block on itself. Cycles/dangling ids are tolerated (permissive).
          blockedBy: command.blockedBy.filter((id) => id !== command.threadId),
          updatedAt: occurredAt,
        },
      };
    }

    case "thread.turn.start": {
      const targetThread = yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      // Dependency gate at the command boundary: the FIRST turn of a dep-blocked
      // sub-thread may only start once its dependencies are satisfied. This
      // closes the UI bypass (opening a `blocked`/`planned` child and sending a
      // message starts it before its deps are `done`). The dispatcher passes
      // naturally (it only fires when deps are satisfied); root threads and
      // every subsequent turn are unaffected. Keying purely off current
      // dep-satisfaction preserves the override path: clearing a child's deps
      // lets the dispatcher auto-promote it.
      if (
        targetThread.parentThreadId !== null &&
        !targetThread.messages.some((message) => message.role === "user") &&
        !areDependenciesSatisfied(
          targetThread,
          new Map(readModel.threads.map((thread) => [thread.id, thread] as const)),
        )
      ) {
        return yield* new OrchestrationCommandInvariantError({
          commandType: command.type,
          detail: `Sub-thread '${command.threadId}' cannot start its first turn until every dependency is done.`,
        });
      }
      const sourceProposedPlan = command.sourceProposedPlan;
      const sourceThread = sourceProposedPlan
        ? yield* requireThread({
            readModel,
            command,
            threadId: sourceProposedPlan.threadId,
          })
        : null;
      const sourcePlan =
        sourceProposedPlan && sourceThread
          ? sourceThread.proposedPlans.find((entry) => entry.id === sourceProposedPlan.planId)
          : null;
      if (sourceProposedPlan && !sourcePlan) {
        return yield* new OrchestrationCommandInvariantError({
          commandType: command.type,
          detail: `Proposed plan '${sourceProposedPlan.planId}' does not exist on thread '${sourceProposedPlan.threadId}'.`,
        });
      }
      if (sourceThread && sourceThread.projectId !== targetThread.projectId) {
        return yield* new OrchestrationCommandInvariantError({
          commandType: command.type,
          detail: `Proposed plan '${sourceProposedPlan?.planId}' belongs to thread '${sourceThread.id}' in a different project.`,
        });
      }
      const userMessageEvent: Omit<OrchestrationEvent, "sequence"> = {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.message-sent",
        payload: {
          threadId: command.threadId,
          messageId: command.message.messageId,
          role: "user",
          text: command.message.text,
          attachments: command.message.attachments,
          turnId: null,
          streaming: false,
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
      const turnStartRequestedEvent: Omit<OrchestrationEvent, "sequence"> = {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        causationEventId: userMessageEvent.eventId,
        type: "thread.turn-start-requested",
        payload: {
          threadId: command.threadId,
          messageId: command.message.messageId,
          ...(command.modelSelection !== undefined
            ? { modelSelection: command.modelSelection }
            : {}),
          ...(command.titleSeed !== undefined ? { titleSeed: command.titleSeed } : {}),
          runtimeMode: targetThread.runtimeMode,
          interactionMode: targetThread.interactionMode,
          ...(sourceProposedPlan !== undefined ? { sourceProposedPlan } : {}),
          createdAt: command.createdAt,
        },
      };
      if (command.setRunning !== true) {
        return [userMessageEvent, turnStartRequestedEvent];
      }
      // Atomic kickoff (D-core child promotion): emit the `running` status-set in
      // the SAME command as the turn-start so both land in one engine
      // transaction. A crash can no longer leave the child with a started turn
      // but a status stuck at `planned`. Only the dispatcher sets `setRunning`;
      // normal/user/agent turn-starts and the requireIdle wake path never do.
      const statusSetEvent: Omit<OrchestrationEvent, "sequence"> = {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        causationEventId: turnStartRequestedEvent.eventId,
        type: "thread.status-set",
        payload: {
          threadId: command.threadId,
          status: "running",
          updatedAt: command.createdAt,
        },
      };
      return [userMessageEvent, turnStartRequestedEvent, statusSetEvent];
    }

    case "thread.turn.interrupt": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.turn-interrupt-requested",
        payload: {
          threadId: command.threadId,
          ...(command.turnId !== undefined ? { turnId: command.turnId } : {}),
          createdAt: command.createdAt,
        },
      };
    }

    case "thread.approval.respond": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
          metadata: {
            requestId: command.requestId,
          },
        })),
        type: "thread.approval-response-requested",
        payload: {
          threadId: command.threadId,
          requestId: command.requestId,
          decision: command.decision,
          createdAt: command.createdAt,
        },
      };
    }

    case "thread.user-input.respond": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
          metadata: {
            requestId: command.requestId,
          },
        })),
        type: "thread.user-input-response-requested",
        payload: {
          threadId: command.threadId,
          requestId: command.requestId,
          answers: command.answers,
          createdAt: command.createdAt,
        },
      };
    }

    case "thread.checkpoint.revert": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.checkpoint-revert-requested",
        payload: {
          threadId: command.threadId,
          turnCount: command.turnCount,
          createdAt: command.createdAt,
        },
      };
    }

    case "thread.session.stop": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.session-stop-requested",
        payload: {
          threadId: command.threadId,
          createdAt: command.createdAt,
        },
      };
    }

    case "thread.session.set": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
          metadata: {},
        })),
        type: "thread.session-set",
        payload: {
          threadId: command.threadId,
          session: command.session,
        },
      };
    }

    case "thread.message.assistant.delta": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.message-sent",
        payload: {
          threadId: command.threadId,
          messageId: command.messageId,
          role: "assistant",
          text: command.delta,
          turnId: command.turnId ?? null,
          streaming: true,
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
    }

    case "thread.message.assistant.complete": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.message-sent",
        payload: {
          threadId: command.threadId,
          messageId: command.messageId,
          role: "assistant",
          text: "",
          turnId: command.turnId ?? null,
          streaming: false,
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
    }

    // v2: streaming reasoning chunks are transient (ReasoningStreamBus) and
    // never become domain events. The only durable reasoning event is the
    // completion, carrying the full accumulated text with REPLACE semantics.
    case "thread.message.reasoning.complete": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.message-reasoning",
        payload: {
          threadId: command.threadId,
          messageId: command.messageId,
          turnId: command.turnId ?? null,
          reasoningText: command.reasoningText,
          reasoningStreaming: false,
          createdAt: command.createdAt,
          updatedAt: command.createdAt,
        },
      };
    }

    case "thread.proposed-plan.upsert": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.proposed-plan-upserted",
        payload: {
          threadId: command.threadId,
          proposedPlan: command.proposedPlan,
        },
      };
    }

    case "thread.turn.diff.complete": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.turn-diff-completed",
        payload: {
          threadId: command.threadId,
          turnId: command.turnId,
          checkpointTurnCount: command.checkpointTurnCount,
          checkpointRef: command.checkpointRef,
          status: command.status,
          files: command.files,
          assistantMessageId: command.assistantMessageId ?? null,
          completedAt: command.completedAt,
        },
      };
    }

    case "thread.revert.complete": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.reverted",
        payload: {
          threadId: command.threadId,
          turnCount: command.turnCount,
        },
      };
    }

    case "thread.report.set": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      const occurredAt = yield* nowIso;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt,
          commandId: command.commandId,
        })),
        type: "thread.report-set",
        payload: {
          threadId: command.threadId,
          reportPath: command.reportPath,
          updatedAt: occurredAt,
        },
      };
    }

    case "thread.activity.append": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      const requestId =
        typeof command.activity.payload === "object" &&
        command.activity.payload !== null &&
        "requestId" in command.activity.payload &&
        typeof (command.activity.payload as { requestId?: unknown }).requestId === "string"
          ? ((command.activity.payload as { requestId: string })
              .requestId as OrchestrationEvent["metadata"]["requestId"])
          : undefined;
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
          ...(requestId !== undefined ? { metadata: { requestId } } : {}),
        })),
        type: "thread.activity-appended",
        payload: {
          threadId: command.threadId,
          activity: command.activity,
        },
      };
    }

    case "thread.turn-start.fail": {
      yield* requireThread({
        readModel,
        command,
        threadId: command.threadId,
      });
      return {
        ...(yield* withEventBase({
          aggregateKind: "thread",
          aggregateId: command.threadId,
          occurredAt: command.createdAt,
          commandId: command.commandId,
        })),
        type: "thread.turn-start-failed",
        payload: {
          threadId: command.threadId,
          detail: command.detail,
          createdAt: command.createdAt,
        },
      };
    }

    default: {
      command satisfies never;
      const fallback = command as never as { type: string };
      return yield* new OrchestrationCommandInvariantError({
        commandType: fallback.type,
        detail: `Unknown command type: ${fallback.type}`,
      });
    }
  }
});

import type { ThreadId } from "@t3tools/contracts";

import type { SidebarThreadSummary } from "../types";
import { hasRunningSignal, resolveBaseColumn, type WorkstreamColumnId } from "./workstreamGraph";

/**
 * Pure presentation logic shared by the Workstream board, cards, and the
 * lazily-loaded graph. Kept JSX-free so the graph chunk (which pulls in the
 * d3-dag layout engine) can import the status/role/format vocabulary without
 * dragging the board components — or vice versa — into either bundle.
 */

export type ChildIndex = ReadonlyMap<ThreadId, SidebarThreadSummary>;

export interface WorkstreamStatus {
  readonly column: WorkstreamColumnId;
  readonly label: string;
  readonly textClass: string;
  readonly borderClass: string;
  readonly bgClass: string;
  readonly dotClass: string;
  readonly leftBorderClass: string;
  readonly graphStroke: string;
  readonly graphFill: string;
}

export const COLUMN_ORDER: ReadonlyArray<WorkstreamColumnId> = [
  "planned",
  "running",
  "blocked",
  "review",
  "error",
  "done",
];

// Statuses a human may set from the card dropdown. `error` is server-only
// (D-liveness): it is a board lane but never an option the user assigns.
export const SETTABLE_STATUSES: ReadonlyArray<WorkstreamColumnId> = COLUMN_ORDER.filter(
  (column) => column !== "error",
