    Effect.andThen(promoteReadyThreads(), wakeEligibleParents()),
    wakeIdleAndErroredChildren(),
  ).pipe(
    Effect.catchCause((cause) => {
      if (Cause.hasInterruptsOnly(cause)) {
        return Effect.failCause(cause);
      }
